content.title:
printf '%s\n' '--- Representative MathJax conversions ---' && sed -n '45,100p' 'wiki/queries/research-补充-okapi-bm25-原始研究与实现变体证据-2026-07-13-160638.md' && printf '%s\n' '--- Diff statistics ---' && git diff --stat && printf '%s\n' '--- Final delimiter totals ---' && printf 'Display blocks: ' && grep -R -h '^\$\$$' --include='*.md' . | wc -l && printf 'Inline math delimiter occurrences: ' && python3 - <<'PY'
from pathlib import Path
import re
count = 0
for path in Path('.').rglob('*.md'):
    if '.git' in path.parts:
        continue
    in_fence = False
    for line in path.read_text(encoding='utf-8').splitlines():
        if line.startswith('```'):
            in_fence = not in_fence
        elif not in_fence:
            count += len(re.findall(r'(?<!\\)\$(?!\$).*?(?<!\\)\$(?!\$)', line))
print(count)
PY

